@patch('bot.weather.httpx.get')
def test_get_alerts_with_results(mock_get, client):
    mock_resp = MagicMock()
    mock_resp.json.return_value = {
        'features': [
            {
                'properties': {
                    'event': 'Winter Storm Warning',
                    'severity': 'Severe',
                    'headline': 'Winter Storm Warning until Friday',
                    'description': 'Heavy snow expected with accumulations of 6-10 inches.',
                    'expires': '2024-01-15T18:00:00Z'
                }
            },
            {
                'properties': {
                    'event': 'Wind Advisory',
                    'severity': 'Moderate',
                    'headline': 'Wind Advisory until Thursday',
                    'description': 'Winds 30-40 mph with gusts to 55 mph.',
                    'expires': '2024-01-14T22:00:00Z'
                }
            }
        ]
    }
    mock_get.return_value = mock_resp
    alerts = client.get_alerts('VA')
    assert len(alerts) == 2
    assert alerts[0]['event'] == 'Winter Storm Warning'
    assert alerts[0]['severity'] == 'Severe'
    assert alerts[1]['event'] == 'Wind Advisory'


